code = """import json

# Load NASDAQ Capital Market data
with open('file_storage/functions.query_db:32.json', 'r') as f:
    nasdaq_stocks = json.load(f)

# Build list of symbols and company names
stocks = []
for stock in nasdaq_stocks:
    symbol = stock['Symbol']
    desc = stock['Company Description']
    # Extract short company name for cleaner output
    company_name = desc
    if '.' in desc and desc.index('.') < 100:  # Avoid too short abbreviations
        company_name = desc.split('.')[0]
    elif ' specializes' in desc:
        company_name = desc.split(' specializes')[0]
    elif ' focuses' in desc:
        company_name = desc.split(' focuses')[0]
    elif ' is ' in desc:
        company_name = desc.split(' is ')[0]
    
    stocks.append({'symbol': symbol, 'company': company_name})

print(f'Total NASDAQ Capital stocks: {len(stocks)}')
print('First 5:', [s['symbol'] for s in stocks[:5]])

# Save the list for querying
result = {'stocks': stocks}
print('__RESULT__:')
print(json.dumps(result)[:1000] + '...')"""

